codeExamples.regoHitlL3:
package ai.gov.autonomy

default allow = false

# Require HITL approval for any L3+ autonomous action
allow {
  input.action.type != "autonomous_action"
}

allow {
  input.action.type == "autonomous_action"
  input.subject.agent.autonomyLevel == "L3"
  input.context.hitlApproval.verified == true
  input.context.hitlApproval.signer in {"AISRB", "CAIO"}
}

violation[msg] {
  input.action.type == "autonomous_action"
  input.subject.agent.autonomyLevel == "L3"
  not input.context.hitlApproval.verified
  msg := "L3 autonomy requires HITL verified approval (EU AI Act Art. 14)"
}

codeExamples.regoEuAiActProhibited:
package ai.gov.eu_ai_act

# Deny any use case classified as prohibited under Art. 5
deny[msg] {
  input.resource.useCase in {
    "social_scoring_government",
    "real_time_remote_biometric_law_enforcement",
    "emotion_recognition_workplace",
    "untargeted_face_image_scraping"
  }
  msg := sprintf("EU AI Act Art. 5 prohibits use case %q", [input.resource.useCase])
}

