# Lambda: quarantine-agent-on-anomaly
import json, os, urllib.request, boto3
sm = boto3.client('secretsmanager'); sns = boto3.client('sns')

def handler(event, _ctx):
    agent_id = event['detail']['agentId']
    anomaly  = event['detail']['anomalyScore']
    if anomaly < 0.85:
        return {'status': 'noop'}

    kill_url = os.environ['KILL_SWITCH_BASE'] + f"/{agent_id}"
    req = urllib.request.Request(kill_url, method='POST')
    req.add_header('Authorization', 'Bearer ' + _get_secret('KILL_TOKEN'))
    urllib.request.urlopen(req, timeout=5)

    _snapshot_trajectory(agent_id)
    _open_incident(agent_id, anomaly)
    _notify_slack(agent_id, anomaly)
    return {'status': 'quarantined', 'agentId': agent_id}

def _get_secret(name):
    return json.loads(sm.get_secret_value(SecretId=name)['SecretString'])['value']

def _snapshot_trajectory(agent_id):
